144	template <typename RetType, size_t N> Expect<RetType> FileMgr::readSN() {
145	  static_assert(N >= 8, "The N of S_N must have at least length of a byte");
146	  static_assert(8 * sizeof(RetType) >= N,
147	                "RetType cannot hold the full range of S_N");
148	  static_assert(std::is_signed_v<RetType>,
149	                "RetType of S_N must be signed type");
150	
151	  if (Status != ErrCode::Value::Success) {
152	    return Unexpect(Status);
153	  }
154	  // Set the flag to the start offset.
155	  LastPos = Pos;
156	
157	  // Read and decode S_N.
158	  RetType Result = 0;
159	  size_t Offset = 0;
160	  size_t RemainingBits = N;
161	  while (true) {
162	    if (RemainingBits <= 0) {
163	      Status = ErrCode::Value::IntegerTooLong;
164	      return Unexpect(Status);
165	    }
166	
167	    // In the rest logic, RemainingBits must be at least 1.
168	    EXPECTED_TRY(testRead(1));
169	    WasmEdge::Byte Byte = Data[Pos++];
170	
171	    const WasmEdge::Byte HighestBitMask = 1 << 7;
172	    const WasmEdge::Byte SecondHighestBitMask = 1 << 6;
173	    if (Byte & HighestBitMask) {
174	      // The byte has leading 1. It contains 7 bits payload.
175	
176	      if (unlikely(RemainingBits < 7)) {
177	        Status = ErrCode::Value::IntegerTooLong;
178	        return Unexpect(Status);
179	      }
180	
181	      std::make_unsigned_t<RetType> Payload =
182	          Byte & (~HighestBitMask); // & 0b01111111
183	      Result |= (Payload << Offset);
184	      Offset += 7;
185	      RemainingBits -= 7;
186	    } else {
187	      // The byte has leading 0. It will be the last byte.
188	
189	      // The number of bits that take effect in the byte. Since RemainingBits
190	      // must be at least 1, EffectiveBits also must be at least 1. It is also
191	      // at most 7.
192	      size_t EffectiveBits = RemainingBits < 7 ? RemainingBits : 7;
193	      std::make_unsigned_t<RetType> Payload = Byte;
194	      if (Byte & SecondHighestBitMask) {
195	        // The byte is signed.
196	        if (Byte >= (1 << 7) - (1 << (EffectiveBits - 1))) {
197	          Payload -= (1 << 7);
198	        } else {
199	          Status = ErrCode::Value::IntegerTooLarge;
200	          return Unexpect(Status);
201	        }
202	      } else {
203	        // The byte is unsigned.
204	        if (Byte >= (1 << (EffectiveBits - 1))) {
205	          Status = ErrCode::Value::IntegerTooLarge;
206	          return Unexpect(Status);
207	        }
208	      }
209	      Result |= (Payload << Offset);
210	      break;
211	    }
212	  }
213	
214	  return Result;
215	}
