321	               ((C == '\xE0' && (Str.data()[I + 1] & '\xA0') == '\x80') ||
322	                // 16 bits UCS, U+0 to U+7FF, FAIL
323	                (C == '\xED' && (Str.data()[I + 1] & '\xA0') == '\xA0')
324	                // 16 bits UCS, U+D800 to U+DFFF, FAIL
325	                )) {
