328	               ((C == '\xF0' && (Str.data()[I + 1] & '\xB0') == '\x80') ||
329	                // 21 bits UCS, U+0 to U+FFFF, FAIL
330	                (C == '\xF4' && (Str.data()[I + 1] & '\xB0') != '\x80') ||
331	                // 21 bits UCS, U+110000 to U+13FFFF, FAIL
332	                (C != '\xF4' && (C & '\xF4') == '\xF4')
